const express = require('express');
const tasksService = require('./service');
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  try {
    const project = await projectsService.getProjectById(req.params.projectId);
    const tasks = await tasksService.getTasksByProjectId(project.id);
    if (req.query.status === 'done') {
      tasks = tasks.filter(task => task.status === 'done');
    }
    res.json({ tasks });
  } catch (error) {
    if (error.code === 'PROJECT_NOT_FOUND') {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.post('/', async (req, res) => {
  const { description } = req.body;
  if (!description) {
    return sendError(res, 400, 'INVALID_INPUT', 'Description is required');
  }
  try {
    const project = await projectsService.getProjectById(req.params.projectId);
    const task = await tasksService.createTask(project.id, description);
    res.status(201).json({ task });
  } catch (error) {
    if (error.code === 'PROJECT_NOT_FOUND') {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid task status');
  }
  try {
    const project = await projectsService.getProjectById(req.params.projectId);
    const task = await tasksService.updateTaskStatus(project.id, req.params.taskId, status);
    res.json({ task });
  } catch (error) {
    if (error.code === 'PROJECT_NOT_FOUND') {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', error.message);
    }
    if (error.code === 'TASK_NOT_FOUND') {
      return sendError(res, 404, 'TASK_NOT_FOUND', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;
