const { randomUUID } = require('node:crypto');
const tasksStore = [];

async function getTasksByProjectId(projectId) {
  return tasksStore.filter(task => task.projectId === projectId);
}

async function createTask(projectId, description) {
  const task = { id: randomUUID(), projectId, description, status: 'todo' };
  tasksStore.push(task);
  return task;
}

async function updateTaskStatus(projectId, taskId, status) {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId && task.projectId === projectId);
  if (taskIndex === -1) {
    throw new Error('Task not found');
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = { getTasksByProjectId, createTask, updateTaskStatus };
